long long solve(long long n, vector<vector<long long>> edges, string label) {
    // Build adjacency list
    vector<vector<long long>> adj(n);
    for (auto& edge : edges) {
        adj[edge[0]].push_back(edge[1]);
        adj[edge[1]].push_back(edge[0]);
    }

    // Use bitmask to represent visited nodes
    // dp[mask] stores the maximum length of palindrome that can be formed with the given mask
    vector<long long> dp(1 << n, 0);

    // Initialize dp for single nodes
    for (long long i = 0; i < n; ++i) {
        dp[1 << i] = 1;
    }

    // Iterate over all possible masks
    for (long long mask = 1; mask < (1 << n); ++mask) {
        // Find the first set bit (starting node)
        long long start = 0;
        for (long long i = 0; i < n; ++i) {
            if (mask & (1 << i)) {
                start = i;
                break;
            }
        }

        // Try all possible next nodes
        for (auto& neighbor : adj[start]) {
            long long new_mask = mask ^ (1 << neighbor);
            if ((mask & (1 << neighbor)) == 0) {
                // Check if the current path can form a palindrome
                long long current_len = dp[mask];
                long long new_len = dp[new_mask];
                // If the first and last characters are the same, we can extend the palindrome
                if (label[start] == label[neighbor]) {
                    new_len = max(new_len, current_len + 2);
                } else {
                    new_len = max(new_len, current_len + 1);
                }
                dp[mask] = max(dp[mask], new_len);
            }
        }
    }

    // Find the maximum value in dp
    long long max_len = 0;
    for (long long i = 0; i < (1 << n); ++i) {
        max_len = max(max_len, dp[i]);
    }

    return max_len;
}

